#!/usr/bin/env python3
import sys
from atcoder import dsu
from bisect import bisect_left
from collections import defaultdict
from collections import deque
# import pypyjit
# pypyjit.set_param(inlining=0)     # or pypyjit.set_param('max_unroll_recursion=-1')

sys.setrecursionlimit(10 ** 6)

INF = 2 ** 64 - 1
MOVE = [(0, 1), (0, -1), (1, 0), (-1, 0)]

# Generated by 2.16.0 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
def main():
    H, W = map(int, input().split())
    F = [input() for _ in range(H)]

    warp_dict = defaultdict(list)
    for y in range(H):
        for x in range(W):
            m = F[y][x]
            if m not in (".", "#"):
                warp_dict[m].append((x, y))

    used = [[False] * W for _ in range(H)]
    used_warp = set()
    
    que = deque()
    que.append([0, 0, 0])
    used[0][0] = True
    

    ans = INF
    while que:
        v, cx, cy = que.popleft()

        if cx == W - 1 and cy == H - 1:
            ans = v
            break

        for mx, my in MOVE:
            nx, ny = cx + mx, cy + my
            if nx < 0 or ny < 0 or nx >= W or ny >= H:
                continue
            if F[ny][nx] == "#" or used[ny][nx]:
                continue
            que.append([v + 1, nx, ny])
            used[ny][nx] = True

        m = F[cy][cx]
        if m != ".":
            if m in used_warp:
                continue
            used_warp.add(m)
            for nx, ny in warp_dict[m]:
                if used[ny][nx]:
                    continue
                que.append([v + 1, nx, ny])
                used[ny][nx] = True
        
    if ans == INF:
        ans = -1
    print(ans)

    

if __name__ == '__main__':
    main()
